ALGORITHM TrapezoidalCUDA
INPUT: a (lower bound), b (upper bound), n (number of subintervals), h (step size)
OUTPUT: Approximate definite integral of f(x) from a to b

// ============================================
// DEVICE KERNEL (runs on GPU)
// ============================================
FUNCTION trapezoidalKernel(a, h, n, partialSums)
 // Declare shared memory for block reduction
 DECLARE shared sdata[blockDim.x]

 // Calculate global thread index
 tid = threadIdx.x
 i = threadIdx.x + blockIdx.x * blockDim.x

 // Each thread computes its contribution
 mySum = 0.0
 IF i <= n THEN
 x_i = a + i * h
 mySum = f(x_i)
 // Apply half weight to boundary points
 IF i == 0 OR i == n THEN
 mySum = mySum * 0.5
 END IF
 END IF

 // Store in shared memory
 sdata[tid] = mySum
 SYNCTHREADS()

 // Parallel reduction within block
 FOR stride = blockDim.x / 2 DOWN TO 1 STEP stride = stride / 2
 IF tid < stride THEN
 sdata[tid] = sdata[tid] + sdata[tid + stride]
 END IF
 SYNCTHREADS()
 END FOR

 // Thread 0 writes block result to global memory
 IF tid == 0 THEN
 partialSums[blockIdx.x] = sdata[0]
 END IF
END FUNCTION

// ============================================
// HOST CODE (runs on CPU)
// ============================================
FUNCTION main()
 // Step 1: Set integration parameters
 READ a, b
 n = 1000000
 h = (b - a) / n

 // Step 2: Calculate grid and block dimensions
 threadsPerBlock = 256
 numBlocks = CEIL((n + 1) / threadsPerBlock)

 // Step 3: Allocate device memory
 d_partialSums = cudaMalloc(numBlocks * sizeof(double))

 // Step 4: Launch CUDA kernel
 sharedMemSize = threadsPerBlock * sizeof(double)
 CALL trapezoidalKernel<<<numBlocks, threadsPerBlock, sharedMemSize>>>(a, h, n, d_partialSums)

 // Step 5: Copy results back to host
 h_partialSums = cudaMemcpy(d_partialSums, numBlocks * sizeof(double))

 // Step 6: Final summation on host
 totalSum = 0.0
 FOR i = 0 TO numBlocks - 1
 totalSum = totalSum + h_partialSums[i]
 END FOR

 // Step 7: Multiply by step size
 integral = h * totalSum

 PRINT integral

 // Step 8: Cleanup
 cudaFree(d_partialSums)
END FUNCTION

// ============================================
// DEVICE FUNCTION (integrand)
// ============================================
FUNCTION f(x)
 RETURN x * x // Example: integrate x^2
END FUNCTION

#include <stdio.h>
#include <cuda_runtime.h>

#define CHECK_CUDA(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 printf("CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
 cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// ============================================
// Device function: The integrand f(x)
// ============================================
__device__ double f(double x) {
 // Example: integrate x^2 from 0 to 1 = 1/3
 return x * x;
}

// ============================================
// CUDA Kernel: Parallel trapezoidal rule
// ============================================
__global__ void trapezoidalKernel(double a, double h, int n, 
 double *partialSums) {
 // Shared memory for block-level reduction
 extern __shared__ double sdata[];

 // Thread indices
 int tid = threadIdx.x;
 int i = threadIdx.x + blockIdx.x * blockDim.x;

 // Each thread computes its contribution
 double mySum = 0.0;
 if (i <= n) {
 double x_i = a + i * h;
 mySum = f(x_i);

 // Half weight for boundary points (first and last)
 if (i == 0 || i == n) {
 mySum *= 0.5;
 }
 }

 // Store in shared memory
 sdata[tid] = mySum;
 __syncthreads();

 // Parallel reduction within block (tree-based)
 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __syncthreads();
 }

 // Thread 0 of block writes partial sum to global memory
 if (tid == 0) {
 partialSums[blockIdx.x] = sdata[0];
 }
}

// ============================================
// Host code: Main function
// ============================================
int main() {
 // Integration parameters
 double a = 0.0; // Lower bound
 double b = 1.0; // Upper bound 
 int n = 1000000; // Number of subintervals
 double h = (b - a) / n;

 // CUDA configuration
 int threadsPerBlock = 256;
 int numBlocks = (n + 1 + threadsPerBlock - 1) / threadsPerBlock;
 int sharedMemSize = threadsPerBlock * sizeof(double);

 printf("CUDA Trapezoidal Rule\n");
 printf("======================\n");
 printf("Integration bounds: [%f, %f]\n", a, b);
 printf("Number of subintervals: %d\n", n);
 printf("Step size (h): %.10f\n", h);
 printf("Threads per block: %d\n", threadsPerBlock);
 printf("Number of blocks: %d\n", numBlocks);

 // Allocate device memory for partial sums
 double *d_partialSums;
 CHECK_CUDA(cudaMalloc(&d_partialSums, numBlocks * sizeof(double)));

 // Launch the kernel
 trapezoidalKernel<<<numBlocks, threadsPerBlock, sharedMemSize>>>(
 a, h, n, d_partialSums);

 // Check for kernel launch errors
 CHECK_CUDA(cudaGetLastError());
 CHECK_CUDA(cudaDeviceSynchronize());

 // Copy partial sums back to host
 double *h_partialSums = (double *)malloc(numBlocks * sizeof(double));
 CHECK_CUDA(cudaMemcpy(h_partialSums, d_partialSums, 
 numBlocks * sizeof(double), 
 cudaMemcpyDeviceToHost));

 // Final summation on host
 double totalSum = 0.0;
 for (int i = 0; i < numBlocks; i++) {
 totalSum += h_partialSums[i];
 }

 // Multiply by step size to get final integral
 double integral = h * totalSum;

 // Exact answer for x^2 from 0 to 1 is 1/3
 double exact = 1.0 / 3.0;

 printf("\nResults:\n");
 printf("-----------\n");
 printf("Computed integral: %.15f\n", integral);
 printf("Exact integral: %.15f\n", exact);
 printf("Absolute error: %.2e\n", fabs(exact - integral));

 // Cleanup
 cudaFree(d_partialSums);
 free(h_partialSums);

 return 0;
}
